    const n = nums.length;
    const sorted = [...nums].sort((a, b) => a - b);
    if (JSON.stringify(nums) === JSON.stringify(sorted)) {
        return 0;
    }

    let k = 0;
    for (let i = 0; i < n; i++) {
        if (nums[i] !== sorted[i]) {
            k |= nums[i] & sorted[i];
        }
    }

    // Now check if this k allows all necessary swaps
    // We need to verify that for all i, nums[i] can be swapped to sorted[i]
    // via some sequence of swaps where each swap satisfies a & b >= k
    // This is equivalent to checking that nums[i] & sorted[i] >= k for all i
    // Because the transitive closure allows swapping if the AND is >= k
    for (let i = 0; i < n; i++) {
        if ((nums[i] & sorted[i]) < k) {
            // Need to find the maximum possible k that satisfies all conditions
            // So we need to find the highest bit where all required ANDs have that bit set
            // Reset k and recompute
            k = 0;
            for (let b = 30; b >= 0; b--) {
                const candidate = k | (1 << b);
                let valid = true;
                for (let i = 0; i < n; i++) {
                    if (nums[i] !== sorted[i] && (nums[i] & sorted[i] & candidate) === 0) {
                        valid = false;
                        break;
                    }
                }
                if (valid) {
                    k = candidate;
                }
            }
            break;
        }
    }

    return k;
}

